args.sparql:
SELECT ?characterLabel WHERE {
  wd:Q174311 wdt:P161 ?film .
  ?film wdt:P1251 ?character .
  ?character rdfs:label ?characterLabel .
  FILTER (LANG(?characterLabel) = 'en')
}

SELECT ?characterLabel WHERE {
  wd:Q174311 p:P161 ?roleStatement .
  ?roleStatement pq:P1251 ?character .
  ?character rdfs:label ?characterLabel .
  FILTER (LANG(?characterLabel) = 'en')
}
